"use client";

import { useMemo, useState } from "react";
import type { Project } from "@/lib/content-data";
import { ProjectCard } from "./project-card";

export function ProjectArchive({ projects }: { projects: Project[] }) {
  const [status, setStatus] = useState<"all" | "ongoing" | "completed">("all");
  const filtered = useMemo(() => status === "all" ? projects : projects.filter((project) => project.status === status), [projects, status]);
  const featured = filtered.filter((project) => project.featured);
  const numbers = new Map(filtered.map((project, index) => [project.id, index + 1]));
  const years = [...new Set(filtered.map((project) => project.year))].sort((a, b) => b - a);
  return <>
    <div className="archive-controls" aria-label="Proje durumuna göre filtrele">
      {[["all", "Tümü"], ["ongoing", "Devam Eden"], ["completed", "Tamamlanan"]].map(([value, label]) => <button key={value} className={`filter-chip${status === value ? " active" : ""}`} onClick={() => setStatus(value as typeof status)}>{label}</button>)}
    </div>
    {featured.length > 0 && <section className="featured-archive"><p className="eyebrow"><span>Vitrin</span>Öne çıkan projeler</p><div className="archive-grid">{featured.map((project) => <ProjectCard key={project.id} project={project} number={numbers.get(project.id)} />)}</div></section>}
    {years.map((year) => <section className="archive-year" key={year}><h2>{year}</h2><div className="archive-grid">{filtered.filter((project) => project.year === year).map((project) => <ProjectCard key={project.id} project={project} number={numbers.get(project.id)} />)}</div></section>)}
  </>;
}
