import Link from "next/link";
import type { Project } from "@/lib/content-data";

export function ProjectCard({ project, large = false, number }: { project: Project; large?: boolean; number?: number }) {
  return (
    <Link href={`/projeler/${project.slug}`} className={`project-card${large ? " project-card-large" : ""}`}>
      <div className="project-image-wrap">
        {/* eslint-disable-next-line @next/next/no-img-element */}
        <img src={project.coverImageUrl} alt={`${project.title} saha çalışması`} className="project-image" />
        <span className={`status-chip ${project.status}`}>{project.status === "ongoing" ? "Devam Ediyor" : "Tamamlandı"}</span>
        {number && <span className="project-list-number">{String(number).padStart(2, "0")}</span>}
        {project.youtubeUrl && <span className="project-video-chip" aria-label="Bu projede video var">▶ Video</span>}
      </div>
      <div className="project-meta"><span>{project.year}</span><span>{project.location}</span></div>
      <div className="project-title-row"><h3>{project.title}</h3><span aria-hidden="true">↗</span></div>
    </Link>
  );
}
